head.script:
scwin.sCurrDate = null;
scwin.sellItemGubun = "";
scwin.retrieveSellItemRow = -1;
scwin.retrieveMasterBlRow = -1;

scwin.sLoUpperLobranCd = null;

scwin.gr_result4_currentRow = -1;
scwin.gr_result2_currentRow = -1;
scwin.gr_results1_click = true;
scwin.gr_results2_click = true;

/**
 * event
 * @name onpageload
 * @description 화면로딩시
 */
scwin.onpageload = async function () {
    // 세션정보 가져오기
    scwin.sLoUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd") ?? "";
    scwin.sCurrDate = $c.date.getServerDateTime("yyyyMMdd");
    $c.sbm.execute(sbm_RetreiveLoBranCMD);

    const codeOptions = [
        { grpCd: "LO102", compID: "gr_results4:sellUnitCd" },
        { grpCd: "FS500", compID: "gr_results4:dcsnClsCd" },
    ];
    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);

    gr_results2.setUserData("gridName", "타창고작업오더정보");

    //버튼제어
    $c.gus.cfDisableBtnOnly([btn_RetrieveMasterBlTransRateAllocation, btn_CancelMasterBlTransRateAllocation, btn_RetrieveSellingItem, btn_save]);
    acb_dtGbn.setValue('T');
};

/**
 * method
 * @name onUdcCompleted
 * @description
 */
scwin.onUdcCompleted = async function () {
    ed_wrkPlCd.options.fixLength = "5";

    ed_wrkStDt.setValue(scwin.sCurrDate);
    ed_wrkEndDt.setValue(scwin.sCurrDate);

    let param = $c.data.getParameter();
    const mrn = param.pmrn ?? "";
    ed_cargoMgntNo1.setValue(mrn);
    ed_cargoMgntNo2.setValue(param.pmsn ?? "");
    ed_cargoMgntNo3.setValue(param.phsn ?? "");
    ed_cntrNo.setValue(param.pcntrNo ?? "");
    ed_odrNo.setValue(param.podrNo ?? "");
    if (mrn != "") {
        await scwin.f_Retrieve(-1);
    }
};

/**
 * method
 * @name f_buttonDisable
 * @description
 */
scwin.f_buttonDisable = function () {
    $c.gus.cfDisableBtnOnly([btn_deleteAll, btn_deleteCancle, btn_delete, btn_cancle]); //$c.gus.cfDisableBtnOnly
};

/**
 * method
 * @name f_buttonEnable
 * @description
 */
scwin.f_buttonEnable = function () {
    $c.gus.cfEnableBtnOnly([btn_deleteAll, btn_deleteCancle, btn_delete, btn_cancle]); //$c.gus.cfEnableBtnOnly
};

/**
 * method
 * @name f_Retrieve
 * @description 조회
 */
scwin.f_Retrieve = async function (row) {
    scwin.f_buttonEnable();
    if (!await $c.gus.cfValidate([grp_searchCondition])) {
        return;
    }

    // dma_search.setJSON({
    //     "wrkPlCd": ed_wrkPlCd.getValue(),
    //     "cntrNo": ed_cntrNo.getValue(),
    //     "mblNo": ed_mblNo.getValue(),
    //     "hblNo": ed_hblNo.getValue(),
    //     "cargoMgntNo1": ed_cargoMgntNo1.getValue(),
    //     "cargoMgntNo2": ed_cargoMgntNo2.getValue(),
    //     "cargoMgntNo3": ed_cargoMgntNo3.getValue(),
    //     "wrkStDt": ed_wrkStDt.getValue(),
    //     "wrkEndDt": ed_wrkEndDt.getValue(),
    //     "dtGbn": acb_dtGbn.getValue(),
    //     "lobranCd": acb_lobran.getValue(),
    //     "odrNo": ed_odrNo.getValue(), //오더번호;
    // });
    ds_results1.removeAll();
    ds_results2.removeAll();
    ds_results3.removeAll();
    ds_results4.removeAll();
    let rowCnt = ds_results1.getRowCount();
    tbx_totalRows1.setValue(rowCnt);
    rowCnt = ds_results2.getRowCount();
    tbx_totalRows2.setValue(rowCnt);
    rowCnt = ds_results3.getRowCount();
    tbx_totalRows3.setValue(rowCnt);
    rowCnt = ds_results4.getRowCount();
    tbx_totalRows4.setValue(rowCnt);

    scwin.retrieveMasterBlRow = row;
    $c.sbm.execute(sbm_search);
};

/**
 * method
 * @name f_chkOpenCommonPopUp
 * @description 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 */
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

/**
 * method
 * @name f_openCommonPopUp
 * @description 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
 */
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    let pWhere = null;
    switch (disGubun) {
        case 1:
            udc_wrkPl.cfCommonPopUp(scwin.udc_wrkPl_popup_callback, pCode, pName, pClose, null, null, null, null, "," + acb_lobran.getValue() + ",", null, null, null, null); // 작업장
            break;

        case 2:	//중기종류(grid)
            pCode = pCode.replace(/\s*$/, '');
            udc_clntHeavyMachineryInfo.cfCommonPopUp(scwin.udc_clntHeavyMachineryInfo_popup_callback, pCode, pName, 'T', null, null, null, null, null, 420, 500, null, null); // 중기LIST
            break;

        case 3:
            pCode = pCode.replace(/\s*$/, '');
            pWhere = "2,4,,," + ds_results2.getCellData(scwin.gr_result2_currentRow, "bilgClntNo");
            // 품명 코드팝업
            udc_commInfo.cfCommonPopUp(scwin.udc_commInfo_popup_callback	// XML상의 SELECT ID
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , pWhere					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "품명,품명코드,품명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
    }
};

/**
 * method
 * @name udc_wrkPl_popup_callback
 * @params {Array}  rtnList
 * @description 팝업 콜백 함수
 */
scwin.udc_wrkPl_popup_callback = function (rtnList) {
    if (rtnList != null && rtnList[0] != 'N/A') {
        ed_wrkPlCd.setValue(rtnList[0]);	//작업장코드
        ed_wrkPlNm.setValue(rtnList[1]);	//작업장명
    }
};

/**
 * method
 * @name udc_clntHeavyMachineryInfo_popup_callback
 * @params {Array}  rtnList
 * @description 팝업 콜백 함수
 */
scwin.udc_clntHeavyMachineryInfo_popup_callback = function (rtnList) {
    if (rtnList != null) {
        ds_results4.setCellData(scwin.gr_result4_currentRow, "eqKndCd", rtnList[0]);    //중기종류코드
        ds_results4.setCellData(scwin.gr_result4_currentRow, "eqKndNm", rtnList[1]);	//중기종류명
        ds_results4.setCellData(scwin.gr_result4_currentRow, "eqNrmCd", rtnList[2]);	//중기규격코드
        ds_results4.setCellData(scwin.gr_result4_currentRow, "eqNrmNm", rtnList[3]);	//중기규격
    }
};

/**
 * method
 * @name udc_commInfo_popup_callback
 * @params {Array}  rtnList
 * @description 팝업 콜백 함수
 */
scwin.udc_commInfo_popup_callback = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            ds_results2.setCellData(scwin.gr_result2_currentRow, "commCd", rtnList[0]);	//품명코드
            ds_results2.setCellData(scwin.gr_result2_currentRow, "commNm", rtnList[1]);	//품명
        }
    } else {
        ds_results2.setCellData(scwin.gr_result2_currentRow, "commCd", "");	//품명코드
        ds_results2.setCellData(scwin.gr_result2_currentRow, "commNm", "");	//품명
    }
};

/**
 * method
 * @name f_FieldClear
 * @description 조회조건 필드 Clear
 */
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(grp_searchCondition, null);
    ed_wrkStDt.setValue(scwin.sCurrDate);
    ed_wrkEndDt.setValue(scwin.sCurrDate);

    acb_lobran.setValue(scwin.sLoUpperLobranCd);
    acb_lobran.focus();
};

/**
 * method
 * @name f_houseBlTransRateRetrieve
 * @description House BL과 TransRate 조회
 */
scwin.f_houseBlTransRateRetrieve = function (row) {
    let rowObj = ds_results1.getRowJSON(row);
    dma_search2.setJSON(rowObj);
    $c.sbm.execute(sbm_houseBlTransRateRetrieve);
};

/**
 * method
 * @name f_retrieveSellingItem
 * @params {Number} row ds_results4의 rowIndex
 * @description 매출항목조회
 */
scwin.f_retrieveSellingItem = async function (row) {
    let results2Row = ds_results2.getRowJSON(gr_results2.getFocusedRowIndex());
    if (!ds_results4.getRowCount()) {
        if (results2Row.wrkWt == 0 && results2Row.wrkCbm == 0) {
            await $c.win.alert("협정물량의 중량 또는 CBM을 입력하십시오.");
            return;
        }
    }

    let cntrCommCd = "";
    let results4Row = ds_results4.getRowJSON(row);
    if (results4Row.sellItemCd == "0278") {
        cntrCommCd = "30000036";
    } else if (results4Row.sellItemCd == "0279") {
        cntrCommCd = "30000038";
    }

    if (row >= 0) {
        //제지매출20 ||  제지매출40  ||  중기일용료  ||  보통일용료  ||  장비사용료 || 이송료 || 보세운송수수료
        switch (results4Row.sellItemCd) {
            case "0278":
            case "0279":
            case "0009":
            case "0008":
            case "0003":
            case "0051":
            case "0042":
                if (results4Row.qty == 0) {
                    await $c.win.alert("수량을 0보다 큰 값으로 입력하십시오.");
                    return;
                }
                ds_results4.setCellData(row, "sellVol", results4Row.qty);
                break;
        }
        dma_retrieveSellingItemCond.setJSON({
            "odrNo": results2Row.odrNo, //오더번호
            "commSeq": results2Row.commSeq, //오더품명순번
            "bilgLodeptCd": ds_results2.getCellData(0, "bilgLodeptCd"), //청구매출부서
            "fmlaPatternCd": '09', //청구서유형코드
            "fmlaClsCd": '01', //문서서식코드
            "outAdjmPatternCd": '01',  //출고정산유형코드
            "outIntendDt": '',  //출고예정일
            "inIntendDt": '',                      //입고예정일
            "sellItemCd": results4Row.sellItemCd,  //매출항목
            "qty": results4Row.qty,  //출고수량
            "wt": results4Row.wt,   //출고중량
            "cbm": results4Row.cbm, //출고CBM
            "jdgAmt": 0,  //감정가
            "cstmdtAmt": 0,  //관세가
            "cntrCommCd": cntrCommCd,  //컨테이너품명코드
            "eqKndCd": results4Row.eqKndCd,  //중기종류코드
            "eqNrmCd": results4Row.eqNrmCd,  //중기규격코드
        });
        scwin.sellItemGubun = "ONE";
    } else {
        dma_retrieveSellingItemCond.setJSON({
            "odrNo": results2Row.odrNo, //오더번호
            "commSeq": results2Row.commSeq, //오더품명순번
            "bilgLodeptCd": ds_results2.getCellData(0, "bilgLodeptCd"), //청구매출부서
            "fmlaPatternCd": '09', //청구서유형코드
            "fmlaClsCd": '01', //문서서식코드
            "outAdjmPatternCd": '01',  //출고정산유형코드
            "outIntendDt": '',  //출고예정일
            "inIntendDt": '',                      //입고예정일
            "sellItemCd": '',  //매출항목
            "qty": results2Row.wrkQty,  //출고수량
            "wt": results2Row.wrkWt,   //출고중량
            "cbm": results2Row.wrkCbm, //출고CBM
            "jdgAmt": 0,  //감정가
            "cstmdtAmt": 0,  //관세가
            "cntrCommCd": cntrCommCd,  //컨테이너품명코드
            "eqKndCd": "",  //중기종류코드
            "eqNrmCd": "",  //중기규격코드
        });
        scwin.sellItemGubun = "ALL";
    }

    $c.sbm.execute(sbm_retrieveSellingItemAdd);
};

/**
 * method
 * @name f_RetrieveSellItemCombo
 * @description 매출항목 콤보 조회
 */
scwin.f_RetrieveSellItemCombo = function (param1, param2, param3) {
    dma_RetrieveComboCMD.setJSON({
        "sysCd": "OrderOutIntendEBC",
        "queryId": "retrieveSellItem",
        "param1": param1,
        "param2": param2,
        "param3": param3,
    });
    $c.sbm.execute(sbm_RetrieveComboCMD);
};

/**
 * method
 * @name f_SellItem
 * @description 매출항목
 */
scwin.f_SellItem = function (row) {
    dma_search3.setJSON({
        "odrNo": ds_results2.getCellData(row, "odrNo"),
    });
    $c.sbm.execute(sbm_retrieveSellingItem);
};

/** //TODO
 * method
 * @name f_RetrieveMasterBlTransRateAllocation
 * @description 운송료배분
 */
scwin.f_RetrieveMasterBlTransRateAllocation = function () {
    scwin.retrieveMasterBlRow = gr_results1.getFocusedRowIndex();
    let rowObj = ds_results1.getRowJSON(scwin.retrieveMasterBlRow);
    dma_search2.setJSON({
        "odrNo": rowObj.odrNo,
        "mrn": rowObj.mrn,
        "msn": rowObj.msn,
    });
    $c.sbm.execute(sbm_RetrieveMasterBlTransRateAllocation);
};

/**
 * method
 * @name f_Save
 * @description 저장
 */
scwin.f_Save = async function () {
    let cntDelRow = 0;
    if (!await $c.gus.cfValidate([gr_results2])) {
        return;
    }

    let row = gr_results2.getFocusedRowIndex();
    let rowObj = ds_results2.getRowJSON(row);
    if (await $c.win.confirm(MSG_CM_CRM_001)) {
        scwin.retrieveMasterBlRow = gr_results1.getFocusedRowIndex();
        if (rowObj.rowStatus == "D") {
            if (++cntDelRow > 0) {
                if (!await $c.win.confirm("오더번호[" + rowObj.odrNo + "]의 실적을 삭제하시겠습니까?")) {
                    return;
                }
            }
            ds_results2Temp.modifyRowStatus(0, "D"); //delete
            // 작업실적 삭제시 미확정인 매출 모두 삭제
            let matched = ds_results4.getMatchedIndex("dcsnClsCd", "1", true);
            matched = matched.filter((idx) => $c.num.parseInt(ds_results4.getCellData(idx, "sellSeq")) > 0);
            if (matched.length) {
                ds_results4.deleteRows(matched);
            }
        }

        if (ds_results2.getCellData(row, "wrkWt") == 0 && ds_results2.getCellData(row, "wrkCbm") == 0) {
            await $c.win.alert("협정물량의 중량 또는 CBM을 입력하십시오.");
            return;
        }

        ds_results2Temp.setJSON([rowObj], false);

        //jobType
        ds_results2Temp.modifyRowStatus(0, rowObj.rowStatus);
        $c.sbm.execute(sbm_Save);
    }
};

/** //TODO
 * method
 * @name f_CancelMasterBlTransRateAllocation
 * @description 배분취소
 */
scwin.f_CancelMasterBlTransRateAllocation = function () {
    scwin.retrieveMasterBlRow = gr_results1.getFocusedRowIndex();
    let rowObj = ds_results1.getRowJSON(scwin.retrieveMasterBlRow);
    dma_search3.setJSON({
        "odrNo": rowObj.odrNo,
    });
    $c.sbm.execute(sbm_CancelMasterBlTransRateAllocation);
};

/**
 * method
 * @name f_addDataSet
 * @description 매출항목조회 완료후 그리드에 ADD
 */
scwin.f_addDataSet = function (sellItemGubun) {
    if (!ds_resultsSellingItem.getRowCount()) {
        return;
    }

    if (sellItemGubun == "ONE") {
        let row = gr_results4.getFocusedRowIndex();
        if (row < 0) {
            return;
        }
        let sellingItem = ds_resultsSellingItem.getRowJSON(0);
        let rowObj = ds_results4.getRowJSON(row);
        sellingItem.eqKndCd = rowObj.eqKndCd;
        sellingItem.eqKndNm = rowObj.eqKndNm;
        sellingItem.eqNrmCd = rowObj.eqNrmCd;
        sellingItem.eqNrmNm = rowObj.eqNrmNm;
        sellingItem.checkBox = rowObj.checkBox;
        sellingItem.sellSeq = rowObj.sellSeq;
        ds_results4.setRowJSON(row, sellingItem, true);
        return;
    }

    let matched = null;
    let allSellingItems = ds_resultsSellingItem.getAllJSON();
    let doButtonDisable = false;
    let addItems = [];
    let results2Row = ds_results2.getRowJSON(gr_results2.getFocusedRowIndex());
    let results1Row = ds_results1.getRowJSON(gr_results1.getFocusedRowIndex());
    for (let sellingItem of allSellingItems) {
        //중복 첵크
        bAdd = true;

        matched = ds_results4.getMatchedIndex("sellItemCd", sellingItem.sellItemCd, true);
        if (matched.length) {
            continue;
        }
        doButtonDisable = true;

        sellingItem.checkBox = "T";

        // 기타하역료일 경우 할증율을 0으로 셋팅한다. (procedure에는 5.4로 셋팅하고 있음)
        if (sellingItem.sellItemCd == "0997") {
            sellingItem.scRt = 0;

            // 팔레트 기타 인경우 (기타하역료 금액을 8000원으로 셋팅)
            if (results2Row.commCd == "30000042" && results1Row.cntrSizCd == "20") {
                if (results1Row.cntrCount == 1) {
                    // 컨테이너 사이즈가 20 이고 컨테이너 수량이 1인 경우에만  8000원으로 셋팅 ( 2008.04.23)
                    sellingItem.sellAmt = 8000;
                    sellingItem.vatAmt = sellingItem.sellAmt * 0.1;
                    sellingItem.subSum = sellingItem.sellAmt + sellingItem.vatAmt;
                } else if (results1Row.cntrCount == 2) {
                    // 컨테이너 사이즈가 20 이고 컨테이너 수량이 2인 경우에만  15000원으로 셋팅 ( 2008.05.19)
                    sellingItem.sellAmt = 15000;
                    sellingItem.vatAmt = sellingItem.sellAmt * 0.1;
                    sellingItem.subSum = sellingItem.sellAmt + sellingItem.vatAmt;
                }
            }
        }
        addItems.push(sellingItem);
    }

    if (addItems.length) {
        ds_results4.insertJSON(ds_results4.getRowCount(), addItems);
        let rowCnt = ds_results4.getRowCount();
        tbx_totalRows4.setValue(rowCnt);
    }

    if (doButtonDisable) {
        scwin.f_buttonDisable();
    }
};

/**
 * method
 * @name f_calSc
 * @params {Number} row ds_results4의 rowIndex
 * @description 할증율 계산
 */
scwin.f_calSc = function (row) {
    let offInRate = 0; //하차입고료
    let devanningRate = 0; //적출료
    let paperSell20 = 0; //제지매출20
    let paperSell40 = 0; //제지매출40
    let bExistPaperSell = false;  //제지매출 존재여부

    let allData = ds_results4.getAllJSON();
    for (let item of allData) {
        switch (item.sellItemCd) {
            case "0050":    //하차입고료
                offInRate = $c.num.parseFloat(item.sellAmt);
                break;

            case "0179":    //적출료
                devanningRate = $c.num.parseFloat(item.sellAmt);
                break;

            case "0278":    //제지매출20
                paperSell20 = $c.num.parseFloat(item.sellAmt);
                bExistPaperSell = true;
                break;

            case "0279":    //제지매출40
                paperSell40 = $c.num.parseFloat(item.sellAmt);
                bExistPaperSell = true;
                break;
        }
    }


    let rate = 0;  //할증율
    let scRt = 0;  //입력할증율
    let paperSell = Math.max(paperSell20, paperSell40); //제지매출중 큰값
    let results4Row = ds_results4.getRowJSON(row);
    let totSellAmt = null;
    switch (results4Row.sellItemCd) {
        //혹한 혹서 우천 설천 황천
        case "0093":
        case "0094":
        case "0095":
        case "0096":
        case "0097":
            rate = (offInRate + devanningRate) * 0.1;
            break;

        //위험물할증, 장척할증, 난작업할증
        case "0088":
        case "0100":
        case "0086":
        case "0092":
            scRt = $c.num.parseFloat(results4Row.scRt);
            rate = (offInRate + devanningRate) * scRt / 100;
            break;

        case "0098":    //야간할증 황사할증
            rate = (offInRate + devanningRate) * 0.5;
            break;

        case "0089":    //휴일할증
            if (bExistPaperSell) {
                rate = paperSell * 0.5;
            } else {
                rate = (offInRate + devanningRate) * 0.5;
            }
            break;

        case "0090":    //토요할증
            if (bExistPaperSell) {
                rate = paperSell * 0.5;
            } else {
                rate = (offInRate + devanningRate) * 0.5;
            }
            break;

        case "0042":    //보세운송수수료
            rate = $c.num.parseFloat(results4Row.sellUpr) * $c.num.parseFloat(results4Row.qty);
            ds_results4.setCellData(row, "sellVol", results4Row.qty);
            results4Row.sellVol = results4Row.qty;
            break;

        case "0256":    //금액할인
            //공급가액
            totSellAmt = allData.reduce((sum, item) => sum + $c.num.parseFloat(item.sellAmt), 0);    //매출금액 합
            scRt = $c.num.parseFloat(results4Row.scRt);
            rate = totSellAmt * scRt / 100;
            break;

        case "0967":    //황사할증
            rate = Math.round((offInRate + devanningRate) * 0.5);
            ds_results4.setCellData(row, "scRt", 50);       // 할증율
            break;

        case "0997":    //기타하역료
            // 팔레트 기타 인경우 (기타하역료 금액을 8000원으로 셋팅)
            if (ds_results2.getCellData(gr_results2.getFocusedRowIndex(), "commCd") == "30000042") {
                // 컨테이너 사이즈가 20 이고 컨테이너 수량이 1인 경우에만  8000원으로 셋팅 ( 2008.04.23)
                let results1Row = ds_results1.getRowJSON(gr_results1.getFocusedRowIndex());
                if (results1Row.cntrSizCd == "20" && results1Row.cntrCount == 1) {
                    rate = 8000;
                } else if (results1Row.cntrSizCd == "20" && results1Row.cntrCount == 2) {
                    // 컨테이너 사이즈가 20 이고 컨테이너 수량이 2인 경우에만  15000원으로 셋팅 ( 2008.05.19)
                    rate = 15000;
                } else {
                    rate = $c.num.parseFloat(results4Row.sellUpr) * $c.num.parseFloat(results4Row.sellVol);
                }
            } else {
                rate = $c.num.parseFloat(results4Row.sellUpr) * $c.num.parseFloat(results4Row.sellVol);
            }
            break;
    }

    let sellVol = $c.num.parseFloat(results4Row.sellVol);
    if (sellVol != 0) {
        sellVol = rate / sellVol;
    }
    ds_results4.setCellData(row, "sellAmt", rate);       //매출금액
    ds_results4.setCellData(row, "sellUpr", sellVol);       //단가
    ds_results4.setCellData(row, "vatAmt", rate * 0.1);  //부가세
};

/**
 * method
 * @name f_totalCal
 * @description 총합 계산
 */
scwin.f_totalCal = function () {
    let totalRateAmt = 0;  //운송료
    let totalPrebilgRateAmt = 0; //선청구운송료
    let totalSellAmt = 0;  //공급가액

    let results2Row = ds_results2.getRowJSON(gr_results2.getFocusedRowIndex());
    let filtered = ds_results3.getAllJSON().filter((item) => item.mrn == results2Row.mrn && item.msn == results2Row.msn && item.hsn == results2Row.hsn);
    for (let item of filtered) {
        totalRateAmt += $c.num.parseFloat(item.sellAmt);
        totalPrebilgRateAmt += $c.num.parseFloat(item.prebilgSellAmt);
    }

    let allData = ds_results4.getAllJSON();
    for (let item of allData) {
        totalSellAmt += $c.num.parseFloat(item.sellAmt);  //매출금액 합
    }

    let total = totalSellAmt + totalRateAmt - totalPrebilgRateAmt;
    let totalVat = total * 0.1;

    gr_results4.setFooterData("sumSellAmt", total);
    gr_results4.setFooterData("sumVatAmt", totalVat);
    gr_results4.setFooterData("sumSubSum", total + totalVat);
};

/**
