    grdObj.setEventPause(null, false);
};

/**
 * method
 * @name f_AddRow4
 * @description 매출등록 그리드 행추가
 */
scwin.f_AddRow4 = async function () {
    if (!ds_results4.getRowCount()) {
        await $c.win.alert("매출항목조회를 먼저하십시오.");
        return;
    }

    let find = null;
    let allData = ds_results4.getAllJSON();
    for (let item of allData) {
        //적출료    하차입고료
        if (item.sellItemCd == "0179" || item.sellItemCd == "0050") {
            find = item;
        }
        break;
    }

    if (find == null) {
        await $c.win.alert("적출료나 하차입고료를 먼저 입력하십시오.");
        return;
    }

    find.eqKndCd = "";
    find.eqKndNm = "";
    find.eqNrmCd = "";
    find.eqNrmNm = "";
    find.sellUpr = "0";
    find.scRt = "0";
    find.sellAmt = "0";
    find.vatAmt = "0";
    find.subSum = "0";
    find.checkBox = "F";
    find.dcsnClsCd = "1";

    ds_results4.insertJSON(ds_results4.getRowCount(), [find]);
    let rowCnt = ds_results4.getRowCount();
    tbx_totalRows4.setValue(rowCnt);
    gr_results4.setFocusedCell(ds_results4.getRowCount() - 1, gr_results4.getFocusedColumnIndex() ?? 0, false);
};

/**
 * method
 * @name f_calSellAmt
 * @description 매출금액 계산
 */
scwin.f_calSellAmt = function () {
    let row = gr_results4.getFocusedRowIndex();

    let rowObj = ds_results4.getRowJSON(row);
    let sellUpr = $c.num.parseFloat(rowObj.sellUpr); //단가
    let sellVol = $c.num.parseFloat(rowObj.sellVol);
    let sellAmt = sellUpr * sellVol;    //매출금액
    let vatAmt = sellAmt * 0.1; //부가세
    let subSum = sellAmt + vatAmt;  //소계

    ds_results4.setCellData(row, "sellAmt", sellAmt); //매출금액
    ds_results4.setCellData(row, "vatAmt", vatAmt);  //부가세
    ds_results4.setCellData(row, "subSum", subSum); //소계
};

