 */
scwin.sbm_search_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    //for=ds_results1
    let rowCnt = ds_results1.getRowCount();
    tbx_totalRows1.setValue(rowCnt);

    if (rowCnt == 0) {
        if ($c.gus.cfCheckCreateFlag()) {
            $c.gus.cfTurnCreateFlag(false);
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
    } else {
        gr_results1.setColumnColor("transRate", "#007FFF");
        let scroll = scwin.retrieveMasterBlRow;
        let focusRow = scwin.retrieveMasterBlRow;
        if (scwin.retrieveMasterBlRow < 0) {
            focusRow = 0;
            scroll = rowCnt;
        }
        gr_results1.setFocusedCell(focusRow, "mblNo", false);
        gr_results1.setTopRowIndex(scroll, true, false);

        //House BL 과 TransRate 조회
        scwin.f_houseBlTransRateRetrieve(scwin.retrieveMasterBlRow);

    }
    //버튼제어
    $c.gus.cfEnableBtnOnly([btn_RetrieveSellingItem, btn_save]);
};

