/**
 * event
 * @name gr_results2_ontextimageclick
 * @description
 */
scwin.gr_results2_ontextimageclick = async function (row, col) {
    const colid = gr_results2.getColumnID(col);
    if (colid == "stvWrkIndictNo") {
        scwin.gr_result2_currentRow = row;
        let rowObj = ds_results2.getRowJSON(row);
        if (rowObj.wrkDt == "") {
            await $c.win.alert("작업일자를 입력하십시오.");
            return;
        }

        const pWrkIndictNo = rowObj.stvWrkIndictNo.replace(/\s*$/, '');
        ds_results2.setCellData(row, "stvWrkIndictNo", "");
        let arrParam = [
            new Array("하역작업지시번호 검색", "작업지시구분", "작업일자", 'retrieveWrkIndictNoList', "F", 5, "F", "T", 'T1'),
            new Array('T', rowObj.wrkDt, pWrkIndictNo, null, rowObj.dptWrkPlCd),
        ];
        // 팝업 옵션 설정
        let options = {
            id: "wrkIndictPop",
            type: "browserPopup",
            popupName: "하역작업지시번호 검색",
            width: 950,
            height: 530
        };

        //상세화면 호출
        let rtnList = await $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_02_08p.xml", options, arrParam);
        if (rtnList != null) {
            ds_results2.setCellData(row, "stvWrkIndictNo", rtnList[0]);
        } else {
            ds_results2.setCellData(row, "stvWrkIndictNo", "");
        }
    } else if (colid == "commCd") {
        scwin.gr_result2_currentRow = row;
        let rowObj = ds_results2.getRowJSON(row);
        ds_results2.setCellData(row, "commCd", "");
        ds_results2.setCellData(row, "commNm", "");
        scwin.f_openCommonPopUp(3, rowObj.commCd, rowObj.commNm, 'F', 'F');
    }
};

/**
 * event
 * @name gr_results2_onviewchange
 * @description
 */
scwin.gr_results2_onviewchange = function (info) {
    const row = info.rowIndex;
    const colid = info.colId;
    const value = info.newValue;
    switch (colid) {
        case "commCd":
            scwin.gr_result2_currentRow = row;
            if (value == "") {
                ds_results2.setCellData(row, "commCd", "");
                ds_results2.setCellData(row, "commNm", "");
            } else if (info.oldValue != value) {
                ds_results2.setCellData(row, "commCd", "");
                ds_results2.setCellData(row, "commNm", "");
                scwin.f_openCommonPopUp(3, value, '', 'T', 'F');
            }
            break;

        case "commNm":
            scwin.gr_result2_currentRow = row;
            if (value == "") {
                ds_results2.setCellData(row, "commCd", "");
                ds_results2.setCellData(row, "commNm", "");
            } else if (info.oldValue != value) {
                ds_results2.setCellData(row, "commCd", "");
                ds_results2.setCellData(row, "commNm", "");
                scwin.f_openCommonPopUp(3, '', value, 'T', 'F');
            }
            break;
    }
};

