/**
 * event
 * @name gr_results4_oncellclick
 * @description
 */
scwin.gr_results4_oncellclick = async function (row, col, colid) {
    if (ds_results4.getRowStatus(row) != "C" && ds_results4.getCellData(row, "dcsnClsCd") != "1") {
        await $c.win.alert((row + 1) + "번째줄은 확정된 매출이므로 변경할 수 없습니다.");
        return;
    }

    let bSellItem = false;
    if (colid == "checkBox") {
        let rowObj = ds_results4.getRowJSON(row);
        if (rowObj.checkBox == "T") {
            let allData = ds_results4.getAllJSON();
            for (let item of allData) {
                //적출료    하차입고료
                if (item.sellItemCd == "0179" || item.sellItemCd == "0050") {
                    bSellItem = true;
                }
                break;
            }

            if (!bSellItem) {
                ds_results4.setCellData(row, "checkBox", "F");
                await $c.win.alert("적출료나 하차입고료를 먼저 입력하십시오.");
                return;
            }

            switch (rowObj.sellItemCd) {
                case "0098":    //0098	야간할증
                case "0089":    //0089	휴일할증
                case "0090":    //0090	토요할증
                case "0094":    //0094	혹서할증
                case "0093":    //0093	혹한할증
                case "0095":    //0095	우천할증
                case "0096":    //0096	설천할증
                case "0097":    //0097	황천할증
                case "0088":    //0088  위험물할증
                case "0042":    //0042  보세운송수수료
                case "0100":    //0100  장척할증
                case "0256":    //0256  금액할인
                case "0086":    //0086  중량할증
                case "0092":
                case "0967":
                case "0997":    //0997   기타하역료
                    //할증율계산
                    scwin.f_calSc(row);
                    break;
                default:
                    //매출항목조회
                    await scwin.f_retrieveSellingItem(row);
                    break;
            }
        }
    } else if (colid == "scRt") {
        let rowObj = ds_results4.getRowJSON(row);
        switch (rowObj.sellItemCd) {
            case "0088":    //0088    위험물할증
            case "0100":    //0100  장척할증
            case "0256":    //0256  금액할인
            case "0086":    //0086  중량할증
            case "0092":
                gr_results4.setColumnReadOnly('scRt', false);
                break;
            default:
                gr_results4.setColumnReadOnly('scRt', true);
                break;
        }
    }
};

/**
 * event
 * @name gr_results4_onrowindexchange
 * @description
 */
scwin.gr_results4_onrowindexchange = function (row, oldRow) {
    if (ds_results4.getRowStatus(row) == "C") {
        gr_results4.setColumnReadOnly('checkBox', false);
        gr_results4.setColumnReadOnly('sellItemCd', false);
        gr_results4.setColumnReadOnly('sellUnitCd', false);
        gr_results4.setColumnReadOnly('eqKndCd', false);
        gr_results4.setColumnReadOnly('eqKndNm', false);
        gr_results4.setColumnReadOnly('sellUpr', false);
        gr_results4.setColumnReadOnly('scRt', false);
        gr_results4.setColumnReadOnly('sellVol', false);
        gr_results4.setColumnReadOnly('qty', false);
        gr_results4.setColumnReadOnly('wt', false);
        gr_results4.setColumnReadOnly('cbm', false);
    } else {
        if (ds_results4.getCellData(row, "dcsnClsCd") != "1") {
            gr_results4.setColumnReadOnly('checkBox', true);
            gr_results4.setColumnReadOnly('sellItemCd', true);
            gr_results4.setColumnReadOnly('sellUnitCd', true);
            gr_results4.setColumnReadOnly('eqKndCd', true);
            gr_results4.setColumnReadOnly('eqKndNm', true);
            gr_results4.setColumnReadOnly('sellUpr', true);
            gr_results4.setColumnReadOnly('scRt', true);
            gr_results4.setColumnReadOnly('sellVol', true);
            gr_results4.setColumnReadOnly('qty', true);
            gr_results4.setColumnReadOnly('wt', true);
            gr_results4.setColumnReadOnly('cbm', true);
            return;
        } else {
            gr_results4.setColumnReadOnly('checkBox', false);
            gr_results4.setColumnReadOnly('sellItemCd', true);
            gr_results4.setColumnReadOnly('sellUnitCd', false);
            gr_results4.setColumnReadOnly('eqKndCd', false);
            gr_results4.setColumnReadOnly('eqKndNm', false);
            gr_results4.setColumnReadOnly('sellUpr', false);
            gr_results4.setColumnReadOnly('scRt', false);
            gr_results4.setColumnReadOnly('sellVol', false);
            gr_results4.setColumnReadOnly('qty', false);
            gr_results4.setColumnReadOnly('wt', false);
            gr_results4.setColumnReadOnly('cbm', false);
        }
    }
};

